    _international_re = re.compile(r'^\+[1-9]\d{6,14}$')

    _us_national_re = re.compile(r'^\d{10}$')
    _us_international_re = re.compile(r'^\+1\d{10}$')

    _gb_national_re = re.compile(r'^0\d{9,10}$')
    _gb_international_re = re.compile(r'^\+44\d{9,10}$')

    def __init__(self, country: Optional[str] = None):
        """
        Args:
            country: ISO 3166-1 alpha-2 country code used to apply country-specific validation rules,
                if omitted, generic phone number validation is used.

        ```py title="IsPhoneNumber"
        from dirty_equals import IsPhoneNumber

        assert '+1-555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber('US')
        assert '+1-555-123-4567' == IsPhoneNumber('US')
        assert '020 7946 0958' == IsPhoneNumber('GB')
        assert '+44 20 7946 0958' == IsPhoneNumber('GB')
        assert '555-123-4567' != IsPhoneNumber('GB')
        assert 1234567890 != IsPhoneNumber
        ```
        """
        self.country = country
        super().__init__(plain_repr('*') if country is None else repr(country))

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False

        digits = self._strip_re.sub('', other)

        if self.country is None:
            return bool(self._national_re.match(digits) or self._international_re.match(digits))

        country = self.country.upper()
        if country == 'US':
            return bool(self._us_national_re.match(digits) or self._us_international_re.match(digits))
        elif country == 'GB':
            return bool(self._gb_national_re.match(digits) or self._gb_international_re.match(digits))
        else:
            return bool(self._international_re.match(digits))

